// ShaderLab Custom — Sphere
uniform vec3  uColor;
uniform float uBright,uEdge;
uniform float uLodFade;
varying float vBlink;
varying float vPhase;
void main(){
  vec3  col=uColor*uBright;
  float alpha=1.0;
  float d=0.0;
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.25)discard;alpha=1.0-smoothstep(uEdge,0.25,d);}
  {vec2 _uv=gl_PointCoord-0.5;d=dot(_uv,_uv);if(d>0.463)discard;if(0.0>0.005&&d<0.0)discard;alpha=1.0-smoothstep(0.378,0.463,d);}
  col=uColor*(1.1*(0.3+vBlink*0.0));
  col=pow(max(col*vec3(0.62,0.62,0.62),vec3(0.0)),vec3(1.0/1.1));
  {float _f=pow(clamp(1.0-abs(vPhase-0.5)*2.0,0.0,1.0),2.22);col+=_f*0.97*vec3(0.63,0.64,0.63);col+=clamp(1.0-_f,0.0,1.0)*col*0.29;}
  alpha=pow(max(alpha,0.0),1.01)*0.98+0.0;
  if(alpha<=0.0)discard;
  gl_FragColor=vec4(col,clamp(alpha,0.0,1.0)*uLodFade);
}
